            </div>
          </div>
        </div>
      )}

      {/* INTERFACE */}
      {stage === 'CORE' && (
        <div className="h-screen flex flex-col animate-in fade-in duration-700">
          <nav className="h-14 border-b border-white/5 flex items-center px-6 justify-between bg-[#050507] backdrop-blur-xl sticky top-0 z-30">
