async function expandLastResponse() {
  if (isProcessing || isSpeaking || !lastOmegaResponse) return;
  isProcessing = true;
  updateUIState('analyzing', 'expanding...');

  try {
    const res = await fetchWithRetry(CHAT_ENDPOINT, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        user: 'Expand your previous response with deeper reasoning and specifics. Go further.',
        history: history.slice(-20),
        sessionId: sessionId || undefined,
      }),
    });

    if (!res.ok) throw new Error('Expand failed');

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let expanded = '';
    let buffer = '';

    while (true) {
      const { value, done } = await reader.read();
      if (done) break;
      buffer += decoder.decode(value, { stream: true });

      // Skip SSE status events
      while (buffer.includes('\n\n')) {
        const idx = buffer.indexOf('\n\n');
        const line = buffer.slice(0, idx).trim();
        if (line.startsWith('data: {"type":"status"')) {
          buffer = buffer.slice(idx + 2);
          continue;
        }
        break;
      }

      if (buffer && !buffer.startsWith('data: {"type":"status"')) {
        expanded += buffer;
        buffer = '';
      }
    }
    expanded += decoder.decode();
    if (buffer) expanded += buffer;
    expanded = expanded.trim();

    if (expanded) {
      history.push({ role: 'omega', text: expanded });
      lastOmegaResponse = expanded;
      await speak(expanded);
    }
  } catch (e) {
    console.error('Expand error:', e);
    isProcessing = false;
    updateUIState('listening');
  }
}

